#include<bits/stdc++.h>
using namespace std;
string s;
struct node
{
    int type;
    int fa=-1,num,x;
    char s;
    int lson=-1,rson=-1;
}a[1000010];
int n;
bool flag[1000010];
int dfs(int x,int f)
{

    if(a[x].type==0)
    {
        a[x].num^=f;
        return a[x].num;
    }
    else
    {
        if(f==1&&a[x].s=='|')
        {
            a[x].s='&';
        }
        else if(f==1)
        {
            a[x].s='|';
        }
    }
    int xx,y;
    xx=dfs(a[x].lson,f^a[a[x].lson].x);
    y=dfs(a[x].rson,f^a[a[x].rson].x);
    if(a[x].s=='|')
    {
        if(xx==1)
        {
            flag[a[x].rson]=1;
        }
        if(y==1)
        {
            flag[a[x].lson]=1;
        }
        return xx|y;
    }
    else
    {
        if(xx==0)
        {
            flag[a[x].rson]=1;
        }
        if(y==0)
        {
            flag[a[x].lson]=1;
        }
        return xx&y;
    }
    return 1;
}
void getflag(int x)
{
    if(a[x].type==0)
    {
        return;
    }
    if(flag[x])
    {
        flag[a[x].lson]=flag[a[x].rson]=1;
    }
    getflag(a[x].lson);
    getflag(a[x].rson);
}
int main()
{
    getline(cin,s);
    int len=s.length();
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        a[i].type=0;
        scanf("%d",&a[i].num);
    }
    int num=0,flag1=0;
    stack<int> stk;
    for(int i=0;i<len;i++)
    {
        // printf("s[%d]=%c\n",i,s[i]);
    }
    for(int i=0;i<len;i++)
    {
        if(s[i]==' '||s[i]=='\n'||s[i]=='\0')
        {
            // printf("i=%d\n",i);
            if(flag1==1)
            {
                flag1=0;
                stk.push(num);
                // printf("num=%d\n",num);
                num=0;
            }
            continue;
        }
        if(s[i]=='x')
        {
            flag1=1;
            continue;
        }
        if(isdigit(s[i]))
        {
            num=num*10+s[i]-'0';
        }
        else
        {
            a[++n].type=1;
            a[n].s=s[i];
            if(s[i]=='&'||s[i]=='|')
            {
                int x=stk.top();
                stk.pop();
                int y=stk.top();
                stk.pop();
                a[n].lson=x;
                a[x].fa=n;
                a[n].rson=y;
                a[y].fa=n;
                stk.push(n);
            }
            else
            {
                a[stk.top()].x=!a[stk.top()].x;
                n--;
            }
            
        }
    }
    int root;
    for(int i=1;i<=n;i++)
    {
        if(a[i].fa==-1)
        {
            root=i;
        }
    }
    root=n;
    int ans=dfs(root,a[root].x);
    getflag(root);
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int x;
        scanf("%d",&x);
        if(!flag[x])
        {
            printf("%d\n",!ans);
        }
        else
        {
            printf("%d\n",ans);
        }
    }
    return 0;
}
